insert into public.recipes (slug, title, icon, category, time_label, description, region, state, data) values
  ('filhote_grelhado', 'Filhote Grelhado', '🐟', 'Almoço · Paraense', '20 min', 'Filhote (peixe amazônico da família do pirarucu) grelhado com limão e azeite.', 'norte', 'PA', '{"ings":[{"n":"Posta de filhote","a":"300 g"},{"n":"Limão, alho, azeite","a":"a gosto"},{"n":"Sal, pimenta-do-reino, coentro","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho, sal e pimenta; deixe 15 min.","Seque bem em papel-toalha antes de grelhar.","Aqueça frigideira com fio de azeite.","Grelhe 4 min cada lado em fogo médio-alto.","Finalize com coentro fresco."],"tip":"Filhote é macio — não passe do ponto. 8 min total já é suficiente."}'::jsonb),
  ('pirarucu_grelhado', 'Pirarucu Grelhado', '🐠', 'Almoço · Amazonense', '25 min', 'Pirarucu grelhado na chapa — o ''bacalhau da Amazônia'', carne branca e firme.', 'norte', 'AM', '{"ings":[{"n":"Posta de pirarucu fresco","a":"300 g"},{"n":"Limão, alho, azeite","a":"a gosto"},{"n":"Sal, pimenta-de-cheiro, coentro","a":"a gosto"}],"steps":["Tempere o pirarucu com limão, alho e sal; deixe 15 min.","Seque bem antes de grelhar.","Aqueça a chapa com fio de azeite.","Grelhe 4 min cada lado em fogo alto.","Finalize com coentro e pimenta-de-cheiro."],"tip":"Se usar pirarucu salgado seco, dessalgar em 3 trocas de água por 24h."}'::jsonb),
  ('tambaqui_grelhado', 'Tambaqui Grelhado', '🐟', 'Almoço · Amazônico', '25 min', 'Tambaqui em costela grelhada com limão — peixe amazônico por excelência.', 'norte', 'AM', '{"ings":[{"n":"Costela de tambaqui","a":"300 g"},{"n":"Limão, alho, pimenta-de-cheiro","a":"a gosto"},{"n":"Sal, cheiro-verde, azeite","a":"a gosto"}],"steps":["Tempere a costela com limão, alho e pimenta-de-cheiro; 20 min.","Grelhe na churrasqueira ou chapa bem quente.","Cozinhe 6 min cada lado (a costela protege do ressecamento).","Finalize com cheiro-verde fresco.","Sirva com farinha de mandioca tostada ao lado."],"tip":"Costela de tambaqui tem osso — peça ao peixeiro pra ''abrir no meio'' pra facilitar o consumo."}'::jsonb),
  ('tambaqui_brasa', 'Tambaqui Assado na Brasa', '🔥', 'Almoço · Especial', '50 min', 'Posta grande de tambaqui assada lentamente na brasa — textura e sabor incomparáveis.', 'norte', 'AM', '{"ings":[{"n":"Postas grandes de tambaqui","a":"400 g"},{"n":"Limão, alho, sal, pimenta","a":"a gosto"},{"n":"Azeite, coentro","a":"a gosto"}],"steps":["Tempere as postas com limão, alho e sal; marinar 30 min.","Prepare brasa bem viva (carvão já queimado).","Coloque as postas em grelha dupla para virar fácil.","Asse 10 min cada lado, longe demais da brasa.","Pincele azeite quando virar.","Finalize com coentro."],"tip":"Brasa MUITO alta queima por fora e deixa cru dentro — afaste a grelha 25-30cm das brasas."}'::jsonb),
  ('charque_feijao_manteiga', 'Charque com Feijão-Manteiga', '🍛', 'Almoço · Amazônico', '1h', 'Charque refogado servido com feijão-manteiga cremoso.', 'norte', 'AM', '{"ings":[{"n":"Charque dessalgado em cubos","a":"200 g"},{"n":"Feijão-manteiga cozido","a":"1,5 xícaras"},{"n":"Cebola, alho, cebolinha","a":"a gosto"},{"n":"Colorau, louro, pimenta","a":"a gosto"}],"steps":["Dessalgue o charque em 3 trocas de água por 24h.","Cozinhe em pressão por 30 min; desfie ou corte em cubos.","Refogue cebola e alho; junte o charque e colorau.","Em panela separada, cozinhe feijão-manteiga com louro.","Misture parte do charque refogado ao feijão; reserve o resto pra montar por cima.","Finalize com cebolinha."],"tip":"Feijão-manteiga é mais cremoso que o carioca — não precisa bater nada pra engrossar."}'::jsonb),
  ('pato_tucupi_light', 'Pato no Tucupi Light', '🦆', 'Jantar · Paraense', '1h30', 'Versão light do pato no tucupi — sem farinha, menos gordura, mesmo sabor do Círio.', 'norte', 'PA', '{"ings":[{"n":"Pato em pedaços magros","a":"300 g"},{"n":"Tucupi (caldo amarelo de mandioca)","a":"500 ml"},{"n":"Jambu (folhas)","a":"1 maço"},{"n":"Alho, cebolinha, pimenta-de-cheiro","a":"a gosto"}],"steps":["Tempere o pato com alho e sal; deixe 30 min.","Doure os pedaços em panela; retire o excesso de gordura.","Acrescente o tucupi filtrado e cozinhe 40 min em fogo baixo.","Branqueie o jambu rapidamente em água fervente.","Adicione o jambu ao caldo nos últimos 5 min.","Sirva com arroz (omitir a farinha reduz calorias)."],"tip":"Jambu causa dormência na boca (efeito ''elétrico'') — é tradição, não estranhe."}'::jsonb),
  ('caldeirada_tucunare', 'Caldeirada de Tucunaré', '🐟', 'Almoço · Amazônico', '40 min', 'Caldeirada tradicional com tucunaré, batata, pimentão e coentro.', 'norte', 'AM', '{"ings":[{"n":"Tucunaré em postas","a":"400 g"},{"n":"Batata em cubos","a":"300 g"},{"n":"Pimentão, tomate, cebola","a":"a gosto"},{"n":"Coentro, limão, azeite, alho","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho, sal; reserve 15 min.","Refogue cebola, alho e pimentão em azeite.","Acrescente tomate e cozinhe até desmanchar.","Adicione as batatas; cubra com água morna.","Após 10 min, disponha as postas sobre os legumes.","Cozinhe tampado por 15 min sem mexer.","Finalize com coentro."],"tip":"Tucunaré tem espinho em Y — retire com pinça ao desossar para evitar surpresas."}'::jsonb),
  ('caldeirada_tucunare_light', 'Caldeirada Leve de Tucunaré', '🐠', 'Jantar · Fit', '30 min', 'Versão leve da caldeirada — menos batata, mais legumes verdes.', 'norte', 'AM', '{"ings":[{"n":"Tucunaré em postas","a":"250 g"},{"n":"Abobrinha, chuchu, cenoura","a":"3 xícaras"},{"n":"Tomate, cebola, coentro","a":"a gosto"},{"n":"Limão, alho, sal, azeite","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho e sal; 15 min.","Refogue cebola e tomate em fio mínimo de azeite.","Junte os legumes em cubos e cubra com água.","Cozinhe por 8 min.","Disponha o peixe por cima; cozinhe tampado 12 min.","Finalize com coentro."],"tip":"Substituindo batata por legumes verdes, vc corta ~200 kcal e aumenta fibras."}'::jsonb),
  ('caldinho_feijao_manteiga', 'Caldinho de Feijão-Manteiga', '🥣', 'Jantar · Aperitivo', '25 min', 'Caldo fino e cremoso de feijão-manteiga batido com temperos.', 'norte', 'AM', '{"ings":[{"n":"Feijão-manteiga cozido","a":"1,5 xícaras"},{"n":"Caldo do feijão","a":"600 ml"},{"n":"Cebola, alho, bacon (opcional)","a":"a gosto"},{"n":"Cheiro-verde, pimenta-de-cheiro","a":"a gosto"}],"steps":["Bata feijão + caldo no liquidificador até ficar sedoso.","Refogue cebola e alho em panela funda.","Acrescente o creme de feijão e ferva por 10 min.","Ajuste sal; a consistência deve ser de caldo, não sopa.","Sirva com cheiro-verde e pimenta-de-cheiro."],"tip":"Feijão-manteiga é naturalmente mais cremoso que carioca ou preto — ideal para caldinhos."}'::jsonb),
  ('frango_tucupi_sem_farinha', 'Frango ao Tucupi sem Farinha', '🐔', 'Almoço · Paraense fit', '20 min', 'Frango grelhado ao tucupi com arroz e jambu refogado — sabor paraense sem os 7 dias de maniva.', 'norte', 'PA', '{"ings":[{"n":"Peito de frango em filés","a":"130 g"},{"n":"Tucupi (caldo amarelo da mandioca)","a":"1/2 xícara"},{"n":"Arroz integral cozido","a":"2 col sopa"},{"n":"Jambu (ou agrião)","a":"1 xícara"},{"n":"Folhas verdes","a":"à vontade"},{"n":"Alho, limão, sal, pimenta-de-cheiro","a":"a gosto"}],"steps":["Tempere o frango com alho, sal e limão; 10 min.","Grelhe em fio de azeite 3-4 min cada lado.","Aqueça o tucupi com alho e pimenta-de-cheiro em outra panela por 5 min.","Refogue o jambu rapidamente (2 min — a erva amortece a boca ao mastigar).","Monte: frango grelhado regado com tucupi, arroz e jambu ao lado."],"tip":"Tucupi pronto de garrafa já vem temperado — sempre fervê-lo antes de usar (mandioca tem traços de cianeto)."}'::jsonb),
  ('moqueca_amazonica', 'Moqueca Amazônica de Peixe', '🐟', 'Almoço · Amazônico', '35 min', 'Moqueca amazônica feita com leite de castanha-do-brasil (sem leite de coco).', 'norte', 'AM', '{"ings":[{"n":"Posta de peixe branco","a":"400 g"},{"n":"Leite de castanha-do-brasil","a":"200 ml"},{"n":"Tomate, cebola, pimentão","a":"a gosto"},{"n":"Coentro, limão, alho, sal","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho, sal; 15 min.","Numa panela, faça camadas: cebola, tomate, pimentão, peixe.","Regue com leite de castanha.","Cozinhe tampado em fogo baixo 20 min sem mexer.","Finalize com muito coentro.","Sirva com arroz e farinha d''água."],"tip":"Pra fazer o leite: bata 100g de castanha-do-brasil com 300ml de água; coe em pano fino."}'::jsonb),
  ('moqueca_amazonica_light', 'Moqueca Amazônica Light', '🐠', 'Jantar · Fit', '25 min', 'Versão reduzida da moqueca amazônica — menos castanha, mais legumes.', 'norte', 'AM', '{"ings":[{"n":"Posta de peixe magro","a":"250 g"},{"n":"Leite de castanha (diluído)","a":"150 ml"},{"n":"Tomate, cebola, pimentão, coentro","a":"a gosto"},{"n":"Limão, alho, sal","a":"a gosto"}],"steps":["Tempere o peixe com limão e alho; 10 min.","Faça camadas em panela antiaderente: legumes, peixe.","Regue com leite de castanha diluído em água.","Cozinhe 15 min tampado.","Finalize com coentro."],"tip":"Leite de castanha diluído (1:1 com água) reduz calorias mas mantém o sabor."}'::jsonb),
  ('omelete_jambu', 'Omelete com Jambu', '🍳', 'Jantar · Paraense', '10 min', 'Omelete simples com jambu refogado — sensação de ''dormência'' típica.', 'norte', 'PA', '{"ings":[{"n":"Ovos","a":"3 unidades"},{"n":"Folhas de jambu branqueadas","a":"1 xícara"},{"n":"Cebolinha, manteiga, sal, pimenta","a":"a gosto"}],"steps":["Branqueie o jambu em água fervente por 2 min; escorra.","Bata os ovos com sal, pimenta e cebolinha.","Aqueça manteiga em frigideira.","Espalhe o jambu na frigideira; despeje os ovos.","Quando firmar, dobre ao meio e sirva."],"tip":"Jambu branqueado perde um pouco da dormência — pra efeito máximo, use cru picado pequeno."}'::jsonb),
  ('pato_no_tucupi', 'Pato no Tucupi Tradicional', '🦆', 'Almoço · Paraense', '2h', 'Pato cozido no caldo de tucupi com jambu — prato do Círio de Nazaré.', 'norte', 'PA', '{"ings":[{"n":"Pato em pedaços","a":"1 kg"},{"n":"Tucupi (caldo de mandioca)","a":"1 litro"},{"n":"Jambu (folhas)","a":"2 maços"},{"n":"Alho, cebolinha, pimenta-de-cheiro","a":"a gosto"}],"steps":["Tempere o pato com alho e sal; asse a 180 °C por 45 min para pegar cor.","Transfira para panela; cubra com tucupi.","Cozinhe em fogo baixo por 1h (até desfiar fácil).","Branqueie o jambu em água fervente por 3 min; escorra.","Adicione o jambu ao caldo nos últimos 10 min.","Sirva com arroz branco e farinha-d''água."],"tip":"Tucupi puro é azedo e amarela os dentes — o cozimento longo neutraliza o efeito."}'::jsonb),
  ('pirarucu_grelhado_limao', 'Pirarucu Grelhado ao Limão', '🐟', 'Almoço · Amazonense fit', '18 min', 'Pirarucu grelhado ao limão com arroz integral, salada de jambu e feijão-de-corda — versão leve sem camadas de batata.', 'norte', 'AM', '{"ings":[{"n":"Filé de pirarucu fresco","a":"130 g"},{"n":"Arroz integral cozido","a":"2 col sopa"},{"n":"Feijão-de-corda cozido","a":"2 col sopa"},{"n":"Jambu c/ tomate (salada)","a":"1 xícara"},{"n":"Alho, limão, coentro, azeite","a":"a gosto"}],"steps":["Tempere o pirarucu com limão, alho e sal; 10 min.","Grelhe em fio de azeite por 3 min cada lado.","Prepare a salada: jambu escaldado 1 min + tomate em cubos + limão.","Aqueça arroz integral e feijão-de-corda.","Monte o prato: pirarucu com limão, arroz, feijão e salada de jambu."],"tip":"Pirarucu fresco grelha rápido — é um peixe firme. Filé congelado descongelado deve ser bem seco antes."}'::jsonb),
  ('sopa_feijao_charque', 'Sopa de Feijão-Manteiga com Charque', '🥣', 'Jantar · Reconfortante', '40 min', 'Sopa encorpada de feijão-manteiga com charque desfiado.', 'norte', 'AM', '{"ings":[{"n":"Feijão-manteiga cozido c/ caldo","a":"2 xícaras"},{"n":"Charque dessalgado desfiado","a":"150 g"},{"n":"Cebola, alho, cheiro-verde","a":"a gosto"},{"n":"Pimenta-de-cheiro","a":"a gosto"}],"steps":["Dessalgue e cozinhe o charque; desfie.","Bata metade do feijão com caldo no liquidificador.","Refogue cebola e alho; junte charque desfiado.","Adicione feijão batido e inteiro + caldo extra.","Cozinhe por 10 min.","Finalize com cheiro-verde e pimenta-de-cheiro."],"tip":"Pimenta-de-cheiro (a amarelinha) tem aroma sem ardência forte — perfeita para acabamento."}'::jsonb),
  ('sopa_legumes_peixe', 'Sopa de Legumes com Macaxeira e Peixe', '🥣', 'Jantar · Nutritivo', '40 min', 'Caldo com macaxeira amassada, legumes e peixe branco desfiado.', 'norte', 'PA', '{"ings":[{"n":"Macaxeira cozida","a":"300 g"},{"n":"Peixe branco cozido e desfiado","a":"200 g"},{"n":"Cenoura, chuchu em cubos","a":"2 xícaras"},{"n":"Cebola, alho, coentro, limão","a":"a gosto"}],"steps":["Cozinhe o peixe em 1 l de água com cebola; reserve o caldo.","Desfie o peixe retirando espinhas com cuidado.","Bata metade da macaxeira com caldo.","Junte o purê ao caldo; adicione cenoura e chuchu.","Cozinhe por 10 min; acrescente o peixe desfiado.","Finalize com coentro e uma pitada de limão."],"tip":"Macaxeira do Norte tem sabor mais intenso que mandioca comum — não troque sem necessidade."}'::jsonb),
  ('tacaca_completo', 'Tacacá Completo', '🥣', 'Jantar · Especial', '45 min', 'Caldo de tucupi com goma de tapioca, jambu e camarão seco — servido na cuia.', 'norte', 'PA', '{"ings":[{"n":"Tucupi","a":"1 litro"},{"n":"Goma de tapioca (polvilho)","a":"1/4 xícara"},{"n":"Jambu branqueado","a":"1 maço"},{"n":"Camarão seco descascado","a":"100 g"},{"n":"Alho, chicória-do-Pará, pimenta","a":"a gosto"}],"steps":["Dissolva a goma em 1 xíc de água fria; ferva mexendo até engrossar.","Aqueça o tucupi com alho e chicória por 15 min.","Hidrate o camarão em água morna; esquente rapidamente.","Branqueie o jambu (2 min em água fervente).","Monte na cuia: goma no fundo, tucupi quente, jambu, camarão.","Sirva imediatamente — tomar sem colher, na borda da cuia."],"tip":"Tacacá legítimo é vendido em barraquinha. Em casa, beba bem quente, com jambu ainda firme."}'::jsonb),
  ('tacaca_light', 'Tacacá Light', '🥣', 'Jantar · Light', '30 min', 'Versão do tacacá sem camarão seco (reduz sódio e calorias).', 'norte', 'PA', '{"ings":[{"n":"Tucupi","a":"600 ml"},{"n":"Goma de tapioca","a":"2 col sopa"},{"n":"Jambu branqueado","a":"1 maço"},{"n":"Alho, chicória-do-Pará","a":"a gosto"}],"steps":["Dissolva a goma em 1/2 xíc de água fria; ferva mexendo até engrossar.","Aqueça o tucupi com alho e chicória 15 min.","Branqueie o jambu por 2 min; escorra.","Monte na cuia: goma, tucupi, jambu.","Sirva bem quente."],"tip":"Sem camarão seco, perde a proteína — combine com algo proteico à parte (ovo, queijo)."}'::jsonb),
  ('camarao_tucupi_light', 'Camarão ao Tucupi Light', '🦐', 'Almoço · Paraense fit', '20 min', 'Camarão ao tucupi sem creme, com arroz integral e quiabo — versão leve do vatapá paraense.', 'norte', 'PA', '{"ings":[{"n":"Camarão grande limpo","a":"130 g"},{"n":"Tucupi (caldo amarelo)","a":"1/2 xícara"},{"n":"Arroz integral cozido","a":"2 col sopa"},{"n":"Quiabo em rodelas","a":"1 xícara"},{"n":"Folhas verdes","a":"à vontade"},{"n":"Alho, limão, coentro, pimenta-de-cheiro","a":"a gosto"}],"steps":["Tempere o camarão com limão, alho e sal; 10 min.","Aqueça o tucupi com alho e pimenta-de-cheiro por 5 min (sempre ferver o tucupi).","Acrescente o camarão ao tucupi; cozinhe 4 min (não passe disso).","Em paralelo, refogue quiabo com alho por 4 min.","Monte: camarão ao tucupi, arroz integral, quiabo e folhas.","Finalize com coentro."],"tip":"Sem pão e leite de castanha, a proteína do camarão fica em destaque — economiza ~150kcal vs vatapá."}'::jsonb),
  ('x_caboquinho', 'X-Caboquinho', '🥪', 'Jantar · Manauara', '15 min', 'Sanduíche amazonense com pão d''água, queijo coalho, pupunha e tucumã.', 'norte', 'AM', '{"ings":[{"n":"Pão d''água ou francês","a":"1 unidade"},{"n":"Queijo coalho em fatias","a":"80 g"},{"n":"Pupunha cozida em fatias","a":"1 unidade"},{"n":"Tucumã em tiras","a":"1/2 xícara"},{"n":"Manteiga, alface","a":"a gosto"}],"steps":["Cozinhe a pupunha em água com sal por 20 min; fatie.","Grelhe o queijo coalho em chapa até dourar.","Corte o pão ao meio e passe manteiga.","Grelhe o pão na chapa até ficar crocante.","Monte: pão, queijo grelhado, pupunha, tucumã, alface.","Feche e sirva imediatamente."],"tip":"Tucumã é o diferencial — amarelo intenso, gordinho, com sabor único. Sem ele, não é caboquinho de verdade."}'::jsonb),
  ('pirarucu_grelhado_ac', 'Pirarucu Grelhado c/ Mandioca Amarela', '🐟', 'Almoço · Acreano', '20 min', 'Pirarucu grelhado ao limão com mandioca amarela cozida — clássico acreano em versão fit.', 'norte', 'AC', '{"ings": [{"n": "Filé de pirarucu fresco", "a": "130 g"}, {"n": "Mandioca amarela em cubos", "a": "120 g"}, {"n": "Limão, alho, coentro", "a": "a gosto"}, {"n": "Folhas verdes", "a": "à vontade"}, {"n": "Azeite, sal, pimenta-de-cheiro", "a": "a gosto"}], "steps": ["Tempere o pirarucu com limão, alho e sal; 10 min.", "Cozinhe a mandioca amarela em água com sal por 18 min.", "Grelhe o pirarucu em fio de azeite 3 min cada lado.", "Sirva o peixe sobre a mandioca, finalize com coentro.", "Acompanhe com folhas verdes e pimenta-de-cheiro."], "tip": "Mandioca amarela (acreana) cozinha mais rápido que a branca — teste o ponto com garfo."}'::jsonb),
  ('pacoca_pirarucu_ac', 'Paçoca de Pirarucu', '🥩', 'Almoço · Quilombola acreano', '18 min', 'Paçoca salgada de pirarucu desfiado com farinha amarela — herança quilombola acreana.', 'norte', 'AC', '{"ings": [{"n": "Pirarucu salgado dessalgado", "a": "130 g"}, {"n": "Farinha de mandioca amarela", "a": "2 col sopa"}, {"n": "Cebola, alho, pimenta-de-cheiro", "a": "a gosto"}, {"n": "Folhas verdes", "a": "à vontade"}, {"n": "Azeite, limão", "a": "a gosto"}], "steps": ["Dessalgue o pirarucu em 2 trocas de água; cozinhe 10 min e desfie.", "Refogue cebola e alho em fio de azeite.", "Acrescente o pirarucu desfiado; aqueça 3 min.", "Incorpore a farinha amarela pouco a pouco mexendo.", "Finalize com pimenta-de-cheiro e limão; sirva com folhas."], "tip": "Farinha amarela da região é mais torrada que a branca — dá cor e sabor característico."}'::jsonb),
  ('caldeirada_dourado_ac', 'Caldeirada de Dourado do Rio Acre', '🐟', 'Almoço · Ribeirinho', '22 min', 'Caldeirada leve de dourado com legumes e coentro — peixe típico dos rios acreanos.', 'norte', 'AC', '{"ings": [{"n": "Posta de dourado", "a": "130 g"}, {"n": "Batata e cenoura em cubos", "a": "1 xícara"}, {"n": "Tomate, cebola, pimentão", "a": "a gosto"}, {"n": "Arroz branco (acompanhamento)", "a": "2 col sopa"}, {"n": "Coentro, alho, limão, azeite", "a": "a gosto"}], "steps": ["Tempere o dourado com limão, alho, sal; 10 min.", "Refogue cebola, alho e pimentão em fio de azeite.", "Acrescente tomate, batata e cenoura; cubra com água.", "Cozinhe 8 min; disponha o peixe por cima e cozinhe tampado mais 10 min.", "Finalize com coentro; sirva com arroz."], "tip": "Dourado tem carne firme — não mexa depois de colocar na panela pra não desfazer."}'::jsonb),
  ('baixaria_light_ac', 'Baixaria Acreana Light', '🍲', 'Almoço · Quilombola', '25 min', 'Versão leve da baixaria quilombola — pirarucu desfiado com mandioca e banana-da-terra, sem fritura.', 'norte', 'AC', '{"ings": [{"n": "Pirarucu dessalgado desfiado", "a": "120 g"}, {"n": "Mandioca cozida em cubos", "a": "100 g"}, {"n": "Banana-da-terra assada", "a": "1/2 unidade"}, {"n": "Cebola, alho, coentro", "a": "a gosto"}, {"n": "Azeite, sal, pimenta", "a": "a gosto"}], "steps": ["Dessalgue e cozinhe o pirarucu; desfie.", "Cozinhe a mandioca; reserve quente.", "Asse a banana-da-terra em fatias a 200 °C por 15 min.", "Refogue cebola e alho em fio de azeite; junte o pirarucu por 3 min.", "Monte o prato em camadas: mandioca, banana, pirarucu refogado.", "Finalize com coentro fresco."], "tip": "Baixaria tradicional é frita — assar reduz ~40% das calorias sem perder o sabor."}'::jsonb),
  ('tambaqui_forno_ac', 'Tambaqui no Forno c/ Legumes', '🐟', 'Jantar · Amazônico', '30 min', 'Postas de tambaqui assadas com legumes da região — jantar leve e nutritivo.', 'norte', 'AC', '{"ings": [{"n": "Posta de tambaqui", "a": "130 g"}, {"n": "Abobrinha, cenoura, pimentão em fatias", "a": "2 xícaras"}, {"n": "Limão, alho, coentro", "a": "a gosto"}, {"n": "Azeite, sal, urucum", "a": "a gosto"}], "steps": ["Tempere o tambaqui com limão, alho, sal e urucum; 15 min.", "Corte os legumes em fatias médias.", "Forre uma assadeira com os legumes; disponha o peixe por cima.", "Regue com fio de azeite; cubra com papel-alumínio.", "Asse a 200 °C por 20 min; retire o alumínio e doure mais 5 min.", "Finalize com coentro."], "tip": "Urucum (colorau) substitui bem o dendê — dá cor acreana sem o peso da gordura."}'::jsonb),
  ('chibe_pirarucu_ac', 'Chibé c/ Pirarucu Desfiado', '🥣', 'Jantar · Ribeirinho', '10 min', 'Chibé tradicional — farinha d''água hidratada — servido com pirarucu desfiado. Jantar leve e rápido.', 'norte', 'AC', '{"ings": [{"n": "Farinha d''água ou amarela", "a": "3 col sopa"}, {"n": "Pirarucu dessalgado desfiado", "a": "80 g"}, {"n": "Água gelada", "a": "1 xícara"}, {"n": "Limão, cebola, coentro", "a": "a gosto"}, {"n": "Sal, pimenta", "a": "a gosto"}], "steps": ["Hidrate a farinha com água gelada por 3 min (chibé).", "Refogue rapidamente o pirarucu desfiado com cebola e fio de azeite.", "Tempere o chibé com limão, sal e coentro picado.", "Sirva o chibé com o pirarucu por cima.", "Acompanhe com pimenta-de-cheiro."], "tip": "Chibé é a comida mais simples do Acre — água, farinha e sal. Adicionar peixe vira refeição."}'::jsonb),
