  ('galinha_caipira_mandioca_ac', 'Galinha Caipira c/ Mandioca', '🐔', 'Almoço · Acreano', '30 min', 'Galinha caipira ensopada servida com mandioca acreana — prato de domingo do sertão.', 'norte', 'AC', '{"ings": [{"n": "Peito de galinha caipira", "a": "130 g"}, {"n": "Mandioca descascada em cubos", "a": "120 g"}, {"n": "Tomate, cebola, alho", "a": "a gosto"}, {"n": "Coentro, cheiro-verde, azeite", "a": "a gosto"}, {"n": "Sal, pimenta, urucum", "a": "a gosto"}], "steps": ["Tempere a galinha com alho, sal e urucum; 15 min.", "Doure em panela; acrescente cebola, tomate e cubra com água.", "Em paralelo, cozinhe a mandioca em água com sal por 20 min.", "Cozinhe a galinha 18 min até ficar macia.", "Sirva a galinha sobre a mandioca cozida.", "Finalize com coentro e cheiro-verde."], "tip": "Mandioca acreana (amarela) é naturalmente amanteigada — não precisa adicionar gordura."}'::jsonb),
