-- Migration 0027: seed de receitas Norte (gerado por scripts/generate-recipes-seed.mjs)
-- 72 receitas curadas para region='norte' (10 por estado: AC, AM, AP, PA, RO, RR, TO +2). UPSERT por slug.

delete from public.recipes where region = 'norte';

on conflict (slug) do update set
  title = excluded.title,
  icon = excluded.icon,
  category = excluded.category,
  time_label = excluded.time_label,
  description = excluded.description,
  region = excluded.region,
  state = excluded.state,
  data = excluded.data;
